const raw = $input.first().json;
const body = raw.body ?? raw;

const company_name = (body.company_name ?? '').trim();
const sector = (body.sector ?? '').trim();
const report_id = body.report_id ?? '';
const user_id = body.user_id ?? '';

if (!company_name || !sector) {
  throw new Error('company_name ve sector zorunludur');
}

return [{ json: { company_name, sector, report_id, user_id } }];

const { company_name, sector, report_id, user_id } = $input.first().json;

const prompt = `Find competitors of "${company_name}" in the "${sector}" sector.

Return ONLY valid JSON, no other text:
{"competitors":[{
  "name":"Company Name",
  "website":"https://example.com",
  "type":"direct",
  "description":"What they do in 2 sentences.",
  "founded":2015,
  "headquarters":"City, Country",
  "employeeRange":"51-200",
  "fundingStage":"series-a",
  "keyFeatures":["feature1","feature2","feature3"],
  "pricing":{"model":"freemium","tiers":[{"name":"Free","price":"$0","features":["f1"]},{"name":"Pro","price":"$29/mo","features":["f1","f2"]}],"hasFreeTrial":true},
  "targetAudience":"Who they target in 1-2 sentences.",
  "sentimentScore":7,
  "strengths":["strength1","strength2","strength3"],
  "weaknesses":["weakness1","weakness2","weakness3"],
  "techStack":["React","AWS"],
  "reviewSummary":"Brief user sentiment summary."
}]}

Rules:
- 5 direct competitors + 2 indirect competitors (7 total)
- type: "direct" or "indirect"
- founded: year as integer or null
- employeeRange: "1-50"|"51-200"|"201-500"|"501-1000"|"1000+"|"unknown"
- fundingStage: "bootstrapped"|"seed"|"series-a"|"series-b"|"series-c+"|"public"|"unknown"
- sentimentScore: integer 1-10
- Only real, known companies`;

return [{
  json: {
    company_name, sector, report_id, user_id,
    requestBody: {
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: 'You are a competitive intelligence expert. Always respond with valid JSON only, no markdown, no explanation. All text values in your JSON response MUST be in English.' },
        { role: 'user', content: prompt }
      ],
      temperature: 0.1,
      max_tokens: 2000,
      response_format: { type: 'json_object' }
    }
  }
}];

const httpResponse = $input.first().json;
const prev = $('Agent1 Prompt').item.json;

let competitors;
try {
  const text = httpResponse.choices[0].message.content;
  competitors = JSON.parse(text).competitors;
  if (!Array.isArray(competitors) || competitors.length === 0) {
    throw new Error('competitors array is empty or missing');
  }
} catch(e) {
  throw new Error('Agent1 parse error: ' + e.message);
}

const { company_name, sector, report_id, user_id } = prev;
const now = new Date().toISOString();

const prompt = `You have competitor data for "${company_name}" in "${sector}":
${JSON.stringify(competitors)}

Generate a complete competitive analysis report. Return ONLY valid JSON:
{
  "companyName":"${company_name}",
  "sector":"${sector}",
  "generatedAt":"${now}",
  "threatLevel":"medium",
  "executiveSummary":"3-4 sentences summary of competitive landscape.",
  "competitiveLandscapeSummary":"2-3 sentences overview.",
  "competitors":[ /* include ALL input competitors with all their original fields */ ],
  "swot":{
    "strengths":["strength from ${company_name}\'s perspective vs competitors (4-5 items)"],
    "weaknesses":["weakness vs competitors (4-5 items)"],
    "opportunities":["market opportunity (4-5 items)"],
    "threats":["threat from competitors (4-5 items)"]
  },
  "marketPositions":[
    {"competitor":"Name","pricePosition":"mid-range","marketShare":"challenger","primaryAdvantage":"brief advantage"}
  ],
  "featureGaps":[
    {"feature":"Feature Name","competitorsHavingIt":["CompA"],"priority":"high","reasoning":"why important"}
  ],
  "winLossScenarios":[
    {"scenario":"Customer needs X","outcome":"win","reason":"because Y","competitorInvolved":"CompA"}
  ],
  "recentIntelligence":[
    {"company":"Name","event":"Event title","summary":"Brief summary","date":"2024-01-15","type":"product","impact":"medium"}
  ],
  "reviewInsights":[
    {"company":"Name","sentimentScore":7,"reviewSummary":"Summary","topPraises":["praise1"],"topComplaints":["complaint1"]}
  ],
  "recommendations":[
    {"title":"Action title","description":"What to do","priority":"high","timeframe":"1-3 months"}
  ],
  "strategicRecommendations":[
    {"title":"Strategic action","description":"Details","priority":"high","timeframe":"3-6 months"}
  ],
  "disclaimer":"This report was AI-generated. Verify before making decisions."
}

Rules:
- threatLevel: "low"|"medium"|"high"|"critical"
- pricePosition: "budget"|"mid-range"|"premium"|"enterprise"
- marketShare: "leader"|"challenger"|"follower"|"niche"
- priority: "critical"|"high"|"medium"|"low"
- timeframe: "1-3 months"|"3-6 months"|"6-12 months"
- outcome: "win"|"loss"
- Include 3-5 items for featureGaps, winLossScenarios, recentIntelligence
- Include 3 recommendations and 3 strategicRecommendations
- reviewInsights: one entry per competitor`;

return [{
  json: {
    company_name, sector, report_id, user_id,
    requestBody: {
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: 'You are a strategic business analyst. Always respond with valid JSON only, no markdown, no explanation. All text values in your JSON response MUST be in English.' },
        { role: 'user', content: prompt }
      ],
      temperature: 0.15,
      max_tokens: 3500,
      response_format: { type: 'json_object' }
    }
  }
}];

const httpResponse = $input.first().json;

let reportData;
try {
  const text = httpResponse.choices[0].message.content;
  reportData = JSON.parse(text);
} catch(e) {
  return [{ json: { success: false, error: 'Final rapor parse hatasi: ' + e.message } }];
}

if (!reportData.companyName || !reportData.competitors || !reportData.swot) {
  return [{ json: { success: false, error: 'Rapor yapisi eksik alanlar iceriyor: ' + JSON.stringify(Object.keys(reportData)) } }];
}

reportData.threatLevel = reportData.threatLevel || 'medium';
reportData.featureGaps = reportData.featureGaps || [];
reportData.winLossScenarios = reportData.winLossScenarios || [];
reportData.recentIntelligence = reportData.recentIntelligence || [];
reportData.reviewInsights = reportData.reviewInsights || [];
reportData.strategicRecommendations = reportData.strategicRecommendations || [];
reportData.recommendations = reportData.recommendations || [];
reportData.disclaimer = reportData.disclaimer || 'This report was AI-generated. Verify before making decisions.';

return [{ json: { success: true, data: reportData } }];
